import React from 'react';
import { MapContainer, TileLayer } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';

// Fix Leaflet default marker icon issue
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
    iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
    iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
    shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
});

// Kerala center coordinates
const KERALA_CENTER = [10.8505, 76.2711];
const DEFAULT_ZOOM = 7;

// Dark theme tile layer
const DARK_TILE_URL = 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png';
const DARK_TILE_ATTRIBUTION = '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> &copy; <a href="https://carto.com/">CARTO</a>';

const BaseMap = ({ children, center = KERALA_CENTER, zoom = DEFAULT_ZOOM, className = '', style = {} }) => {
    return (
        <MapContainer
            center={center}
            zoom={zoom}
            className={className}
            style={{ height: '100%', width: '100%', borderRadius: '1rem', ...style }}
            scrollWheelZoom={true}
            zoomControl={true}
        >
            <TileLayer url={DARK_TILE_URL} attribution={DARK_TILE_ATTRIBUTION} />
            {children}
        </MapContainer>
    );
};

// Custom marker icons
export const createIcon = (color = '#22c55e', size = 24) => {
    return L.divIcon({
        className: 'custom-marker',
        html: `<div style="
            background: ${color};
            width: ${size}px;
            height: ${size}px;
            border-radius: 50% 50% 50% 0;
            transform: rotate(-45deg);
            border: 2px solid white;
            box-shadow: 0 2px 8px rgba(0,0,0,0.4);
        "></div>`,
        iconSize: [size, size],
        iconAnchor: [size / 2, size],
        popupAnchor: [0, -size]
    });
};

export const MARKER_ICONS = {
    camp: createIcon('#3b82f6', 22),       // Blue
    safehome: createIcon('#22c55e', 20),   // Green
    alert: createIcon('#ef4444', 24),       // Red
    earthquake: createIcon('#f97316', 18),  // Orange
};

export { KERALA_CENTER, DEFAULT_ZOOM };
export default BaseMap;

import React, { createContext, useContext, useState, useEffect } from 'react';
import { authAPI } from '../services/api';

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [token, setToken] = useState(localStorage.getItem('token'));
    const [loading, setLoading] = useState(true);

    // On mount, check if we have a stored token and load user
    useEffect(() => {
        const loadUser = async () => {
            if (token) {
                try {
                    const res = await authAPI.getMe();
                    setUser(res.data.data);
                } catch (err) {
                    console.error('Failed to load user:', err);
                    localStorage.removeItem('token');
                    localStorage.removeItem('user');
                    setToken(null);
                    setUser(null);
                }
            }
            setLoading(false);
        };
        loadUser();
    }, [token]);

    const login = async (email, password, role) => {
        try {
            const res = await authAPI.login({ email, password, role });
            const { token: newToken, data } = res.data;
            localStorage.setItem('token', newToken);
            localStorage.setItem('user', JSON.stringify(data));
            setToken(newToken);
            setUser(data);
            return { success: true, data };
        } catch (err) {
            const message = err.response?.data?.message || 'Login failed';
            return { success: false, message };
        }
    };

    const register = async (formData) => {
        try {
            const res = await authAPI.register(formData);
            const { token: newToken, data } = res.data;
            localStorage.setItem('token', newToken);
            localStorage.setItem('user', JSON.stringify(data));
            setToken(newToken);
            setUser(data);
            return { success: true, data };
        } catch (err) {
            const message = err.response?.data?.message || 'Registration failed';
            return { success: false, message };
        }
    };

    const logout = async () => {
        try {
            await authAPI.logout();
        } catch {
            // Ignore errors
        }
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        setToken(null);
        setUser(null);
    };

    const updateProfile = async (data) => {
        try {
            const res = await authAPI.updateProfile(data);
            setUser(res.data.data);
            localStorage.setItem('user', JSON.stringify(res.data.data));
            return { success: true, data: res.data.data };
        } catch (err) {
            const message = err.response?.data?.message || 'Update failed';
            return { success: false, message };
        }
    };

    return (
        <AuthContext.Provider value={{
            user,
            token,
            loading,
            isAuthenticated: !!user,
            login,
            register,
            logout,
            updateProfile
        }}>
            {children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => {
    const context = useContext(AuthContext);
    if (!context) {
        throw new Error('useAuth must be used within an AuthProvider');
    }
    return context;
};

import React, { createContext, useContext, useEffect, useState, useRef } from 'react';
import { AlertTriangle, X } from 'lucide-react';
import api from '../services/api';

const GlobalAlertContext = createContext();

export const GlobalAlertProvider = ({ children }) => {
    const [alerts, setAlerts] = useState([]);
    const previousRiskRef = useRef({});

    useEffect(() => {
        // Function to check for new risks
        const checkRiskUpdates = async () => {
            try {
                const res = await api.get('/alerts/risk-map');
                const riskData = res.data;

                const newAlerts = [];
                const currentRiskMap = {};

                riskData.forEach(d => {
                    const currentRisk = d.risk;
                    const prevRisk = previousRiskRef.current[d.district];

                    // Check if it's a newly elevated risk (Moderate or High)
                    const isNowElevated = currentRisk === 'High' || currentRisk === 'Moderate';
                    const wasElevated = prevRisk === 'High' || prevRisk === 'Moderate';

                    if (isNowElevated && !wasElevated && Object.keys(previousRiskRef.current).length > 0) {
                        // The risk just elevated, and this wasn't the first load
                        newAlerts.push({
                            id: Date.now() + Math.random(),
                            district: d.district,
                            risk: currentRisk,
                            description: d.description,
                            isManual: d.isManualOverride
                        });
                    }

                    currentRiskMap[d.district] = currentRisk;
                });

                // Update the ref for next interval
                previousRiskRef.current = currentRiskMap;

                if (newAlerts.length > 0) {
                    setAlerts(prev => [...prev, ...newAlerts]);
                }
            } catch (err) {
                console.error('Failed to poll risk data:', err);
            }
        };

        // Initial fetch
        checkRiskUpdates();

        // Poll every 15 seconds
        const intervalId = setInterval(checkRiskUpdates, 15000);

        return () => clearInterval(intervalId);
    }, []);

    const dismissAlert = (id) => {
        setAlerts(prev => prev.filter(a => a.id !== id));
    };

    return (
        <GlobalAlertContext.Provider value={{}}>
            {children}

            {/* Global Overlay for Active Alerts */}
            {alerts.length > 0 && (
                <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[9999] flex flex-col gap-4 w-full max-w-md pointer-events-none px-4 font-sans">
                    {alerts.map(alert => (
                        <div key={alert.id} className="pointer-events-auto bg-red-600 border border-red-400 text-white px-6 py-4 rounded-xl shadow-2xl flex items-start gap-4 relative overflow-hidden animate-bounce-in">
                            {/* Background Pulse Effect */}
                            <div className="absolute -top-10 -left-10 w-20 h-20 bg-white/20 rounded-full blur-2xl animate-pulse"></div>

                            <div className="bg-white/20 rounded-full p-2 mt-1 shrink-0 relative z-10">
                                <AlertTriangle className="w-6 h-6 text-white" />
                            </div>

                            <div className="flex-1 relative z-10">
                                <h4 className="font-bold text-lg uppercase tracking-wider mb-1">
                                    Critical Alert
                                </h4>
                                <p className="text-white/90 font-medium leading-relaxed mb-1">
                                    {alert.district} under {alert.risk.toLowerCase()} risk
                                </p>
                                <p className="text-xs text-white/70 mt-2 opacity-80 uppercase tracking-wide">
                                    Priority: {alert.risk}
                                </p>
                            </div>

                            <button
                                onClick={() => dismissAlert(alert.id)}
                                className="bg-black/20 hover:bg-black/40 p-1 rounded-lg transition relative z-10"
                            >
                                <X className="w-5 h-5" />
                            </button>
                        </div>
                    ))}
                </div>
            )}
        </GlobalAlertContext.Provider>
    );
};

export const useGlobalAlert = () => useContext(GlobalAlertContext);

import React, { createContext, useContext, useState, useEffect } from 'react';
import { X, AlertTriangle } from 'lucide-react';

const NotificationContext = createContext();

export const useNotification = () => useContext(NotificationContext);

export const NotificationProvider = ({ children }) => {
    const [notification, setNotification] = useState(null);

    const showNotification = (message, type = 'emergency') => {
        const id = Date.now();
        const newNotif = { id, message, type };
        setNotification(newNotif);

        // Broadcast to other tabs
        // Adding a random component to key to ensure change detection even for same message
        localStorage.setItem('resq-broadcast-alert', JSON.stringify({ ...newNotif, timestamp: Date.now() }));

        setTimeout(() => setNotification(null), 6000);
    };

    useEffect(() => {
        const handleStorageChange = (e) => {
            if (e.key === 'resq-broadcast-alert' && e.newValue) {
                const alert = JSON.parse(e.newValue);
                // 'storage' event fires only on other tabs, which is exactly what we want for "all 3 users"
                setNotification(alert);
                setTimeout(() => setNotification(null), 6000);
            }
        };

        window.addEventListener('storage', handleStorageChange);
        return () => window.removeEventListener('storage', handleStorageChange);
    }, []);

    return (
        <NotificationContext.Provider value={{ showNotification }}>
            {children}
            {notification && (
                <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] w-full max-w-md px-4 pointer-events-none animate-bounce-in">
                    <div className={`
                        pointer-events-auto border text-white px-6 py-4 rounded-xl shadow-2xl flex items-start gap-4 relative overflow-hidden
                        ${notification.type === 'low' ? 'bg-green-600 border-green-400' : ''}
                        ${notification.type === 'medium' ? 'bg-yellow-600 border-yellow-400' : ''}
                        ${notification.type === 'high' ? 'bg-orange-600 border-orange-400' : ''}
                        ${notification.type === 'critical' || notification.type === 'emergency' ? 'bg-red-600 border-red-400' : ''}
                    `}>
                        {/* Background Pulse Effect - only for high/critical */}
                        {(notification.type === 'high' || notification.type === 'critical' || notification.type === 'emergency') && (
                            <div className="absolute -top-10 -left-10 w-20 h-20 bg-white/20 rounded-full blur-2xl animate-pulse"></div>
                        )}

                        <div className="bg-white/20 rounded-full p-2 mt-1 shrink-0">
                            <AlertTriangle className="w-6 h-6 text-white" />
                        </div>
                        <div className="flex-1">
                            <h4 className="font-bold text-lg uppercase tracking-wider mb-1">
                                {notification.type === 'low' ? 'Safety Update' :
                                    notification.type === 'medium' ? 'Advisory' :
                                        notification.type === 'high' ? 'Warning' : 'Critical Alert'}
                            </h4>
                            <p className="text-white/90 font-medium leading-relaxed">{notification.message}</p>
                            <p className="text-xs text-white/70 mt-2 opacity-80 uppercase tracking-wide">
                                Priority: {notification.type === 'emergency' ? 'Critical' : notification.type}
                            </p>
                        </div>
                        <button
                            onClick={() => setNotification(null)}
                            className="bg-black/20 hover:bg-black/40 p-1 rounded-lg transition"
                        >
                            <X className="w-5 h-5" />
                        </button>
                    </div>
                </div>
            )}
        </NotificationContext.Provider>
    );
};

import React, { createContext, useContext, useState, useEffect } from 'react';

const ThemeContext = createContext();

export const ThemeProvider = ({ children }) => {
    // Default to dark mode as per original design
    const [theme, setTheme] = useState('dark');

    useEffect(() => {
        const root = window.document.documentElement;
        if (theme === 'dark') {
            root.classList.add('dark');
        } else {
            root.classList.remove('dark');
        }
    }, [theme]);

    const toggleTheme = () => {
        setTheme((prev) => (prev === 'dark' ? 'light' : 'dark'));
    };

    return (
        <ThemeContext.Provider value={{ theme, toggleTheme }}>
            {children}
        </ThemeContext.Provider>
    );
};

export const useTheme = () => useContext(ThemeContext);

import React, { useEffect, useState } from 'react';
import { Marker, Popup, GeoJSON } from 'react-leaflet';
import { dashboardAPI } from '../../services/api';
import api from '../../services/api'; // For direct marker fetching
import BaseMap, { MARKER_ICONS, createIcon } from '../../components/map/BaseMap';
import keralaGeoJSON from '../../data/kerala-districts.json';

const Dashboard = () => {
    const [stats, setStats] = useState(null);
    const [markers, setMarkers] = useState([]);
    const [riskZones, setRiskZones] = useState([]);
    const [loading, setLoading] = useState(true);
    const [activeFilter, setActiveFilter] = useState('all');

    useEffect(() => {
        const fetchData = async () => {
            try {
                // Fetch stats, live markers, and risk zones concurrently
                const [statsRes, markersRes, riskRes] = await Promise.all([
                    dashboardAPI.getStats(),
                    api.get('/alerts/live-markers').catch(() => ({ data: { data: [] } })),
                    api.get('/alerts/risk-map').catch(() => ({ data: [] }))
                ]);

                setStats(statsRes.data.data);
                setMarkers(markersRes.data.data || []);
                setRiskZones(riskRes.data || []);
            } catch (err) {
                console.error('Failed to load dashboard data:', err);
                if (!stats) {
                    setStats({
                        totalRefugees: 0,
                        activeCamps: 0,
                        lowResourceCamps: 0,
                        totalVolunteers: 0
                    });
                }
            } finally {
                setLoading(false);
            }
        };
        fetchData();
    }, []);

    const districtsAtRisk = riskZones.filter(r => r.risk === 'High' || r.risk === 'Moderate').length;
    const filteredMarkers = activeFilter === 'all' ? markers : markers.filter(m => m.type === activeFilter);

    const statCards = stats ? [
        { title: 'Active Camps', value: stats.activeCamps.toString(), color: 'bg-green-500' },
        { title: 'Districts in Risk', value: `${districtsAtRisk}`, color: 'bg-red-500' },
        { title: 'Volunteers', value: stats.totalVolunteers.toString(), color: 'bg-purple-500' }
    ] : [];

    // GeoJSON styling for moderate/high risk zones
    const styleFeature = (feature) => {
        const district = feature.properties.district;
        const riskData = riskZones.find(r => r.district.toLowerCase() === district.toLowerCase());

        if (!riskData || riskData.risk === 'Safe') {
            return { weight: 0, fillOpacity: 0, opacity: 0 };
        }

        const isHigh = riskData.risk === 'High';
        return {
            fillColor: isHigh ? '#ef4444' : '#facc15',
            weight: 2,
            opacity: 0.8,
            color: isHigh ? '#ef4444' : '#facc15',
            fillOpacity: 0.35,
        };
    };

    const filterFeature = (feature) => {
        const district = feature.properties.district;
        const riskData = riskZones.find(r => r.district.toLowerCase() === district.toLowerCase());
        return riskData && (riskData.risk === 'High' || riskData.risk === 'Moderate');
    };

    return (
        <div className="p-4 sm:p-0">
            <h2 className="text-2xl sm:text-3xl font-bold mb-6 text-white">Overview</h2>

            {loading ? (
                <div className="flex justify-center py-20">
                    <div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
                </div>
            ) : (
                <>
                    <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 sm:gap-6">
                        {statCards.map((stat, idx) => (
                            <div key={idx} className="bg-surface p-4 sm:p-6 rounded-2xl shadow-sm border border-white/10 flex items-center justify-between">
                                <div>
                                    <p className="text-xs sm:text-sm text-gray-400 font-medium">{stat.title}</p>
                                    <p className="text-2xl sm:text-3xl font-bold text-white mt-2">{stat.value}</p>
                                </div>
                                <div className={`w-3 h-3 rounded-full ${stat.color}`}></div>
                            </div>
                        ))}
                    </div>

                    <div className="mt-8 grid grid-cols-1 lg:grid-cols-2 gap-6 sm:gap-8">
                        <div className="bg-surface p-4 sm:p-6 rounded-2xl shadow-sm border border-white/10 h-64 sm:h-96">
                            <h3 className="font-bold text-lg mb-4 text-white">Live Map</h3>
                            <div className="w-full h-[calc(100%-3rem)] rounded-xl overflow-hidden shadow-lg border border-white/5 relative z-0">

                                {/* Filter bar */}
                                <div className="absolute top-3 left-3 z-[999] flex flex-wrap gap-2">
                                    {[
                                        { key: 'all', label: 'All' },
                                        { key: 'camp', label: 'Camps' },
                                        { key: 'safehome', label: 'Safe Homes' },
                                        { key: 'alert', label: 'Alerts' }
                                    ].map(f => (
                                        <button key={f.key} onClick={(e) => { e.stopPropagation(); setActiveFilter(f.key); }}
                                            className={`px-2 py-1 sm:px-3 sm:py-1.5 rounded-lg text-xs font-bold transition ${activeFilter === f.key
                                                ? 'bg-primary text-black shadow-lg'
                                                : 'bg-black/70 text-gray-300 hover:bg-black/90 border border-white/10'}`}>
                                            {f.label}
                                        </button>
                                    ))}
                                </div>

                                <BaseMap>
                                    {riskZones.length > 0 && (
                                        <GeoJSON
                                            key={`risk-${riskZones.length}`}
                                            data={keralaGeoJSON}
                                            style={styleFeature}
                                            filter={filterFeature}
                                        />
                                    )}
                                    {filteredMarkers.map((marker, idx) => (
                                        marker.lat && marker.lng && (
                                            <Marker
                                                key={`marker-${idx}`}
                                                position={[marker.lat, marker.lng]}
                                                icon={MARKER_ICONS[marker.type] || createIcon()}
                                            >
                                                <Popup className="custom-popup">
                                                    <div className="m-0 p-1">
                                                        <div className="font-bold text-sm mb-1">{marker.title}</div>
                                                        <div className="text-xs text-gray-600 mb-1">{marker.district}</div>
                                                        <div className="text-xs">{marker.details}</div>
                                                    </div>
                                                </Popup>
                                            </Marker>
                                        )
                                    ))}
                                </BaseMap>
                            </div>
                        </div>
                        <div className="bg-surface p-4 sm:p-6 rounded-2xl shadow-sm border border-white/10 h-auto lg:h-80 overflow-y-auto">
                            <h3 className="font-bold text-lg mb-4 text-white">Recent Alerts</h3>
                            <ul className="space-y-3">
                                {riskZones.filter(r => r.risk === 'High' || r.risk === 'Moderate').length > 0 ? (
                                    riskZones
                                        .filter(r => r.risk === 'High' || r.risk === 'Moderate')
                                        .sort((a) => a.risk === 'High' ? -1 : 1)
                                        .slice(0, 5)
                                        .map((alert, idx) => (
                                            <li key={idx} className={`p-3 rounded-lg text-xs sm:text-sm border ${alert.risk === 'High' ? 'bg-red-900/30 text-red-400 border-red-500/30' :
                                                'bg-orange-900/30 text-orange-400 border-orange-500/30'
                                                }`}>
                                                {alert.risk === 'High' ? '🔴' : '🟠'} {alert.district} under {alert.risk} risk
                                                <p className="text-[10px] mt-1 text-gray-400 truncate">{alert.description}</p>
                                            </li>
                                        ))
                                ) : (
                                    <li className="p-3 text-gray-500 text-center text-sm border border-dashed border-white/10 rounded-lg">
                                        No active alerts at this time.
                                    </li>
                                )}
                            </ul>
                        </div>
                    </div>
                </>
            )}
        </div>
    );
};

export default Dashboard;

import React, { useState, useEffect, useCallback } from 'react';
import { MapPin, Info, AlertTriangle, Shield, RefreshCw } from 'lucide-react';
import BaseMap from '../../components/map/BaseMap';
import { GeoJSON, useMap } from 'react-leaflet';
import keralaGeoJSON from '../../data/kerala-districts.json';
import api from '../../services/api';
import { useAuth } from '../../context/AuthContext';

const RISK_COLORS = {
    High: '#ef4444',
    Moderate: '#facc15',
    Safe: '#22c55e'
};

const RISK_BG = {
    High: 'bg-red-500/20 border-red-500/30',
    Moderate: 'bg-yellow-500/20 border-yellow-500/30',
    Safe: 'bg-green-500/20 border-green-500/30'
};

const RISK_TEXT = {
    High: 'text-red-400',
    Moderate: 'text-yellow-400',
    Safe: 'text-green-400'
};

// Component to fit map bounds to Kerala
const FitBounds = () => {
    const map = useMap();
    useEffect(() => {
        map.fitBounds([[8.2, 74.8], [12.8, 77.4]], { padding: [20, 20] });
    }, [map]);
    return null;
};

const RiskZoneMap = ({ isPublic = false }) => {
    const { user } = useAuth();
    const [riskData, setRiskData] = useState([]);
    const [selectedZone, setSelectedZone] = useState(null);
    const [loading, setLoading] = useState(true);
    const [geoJsonKey, setGeoJsonKey] = useState(0);
    const [updatingOverride, setUpdatingOverride] = useState(false);

    const isAdmin = user?.role === 'admin' && !isPublic;

    useEffect(() => {
        fetchRiskData();
    }, []);

    const fetchRiskData = async () => {
        setLoading(true);
        try {
            const res = await api.get('/alerts/risk-map');
            setRiskData(res.data);
            setGeoJsonKey(prev => prev + 1);
            if (selectedZone) {
                // Update selected zone data if currently selected
                const updatedZone = res.data.find(d => d.district === selectedZone.district);
                if (updatedZone) setSelectedZone(updatedZone);
            }
        } catch (err) {
            console.error('Failed to fetch risk data:', err);
        } finally {
            setLoading(false);
        }
    };

    const handleOverrideChange = async (district, newRiskLevel) => {
        try {
            setUpdatingOverride(true);
            await api.put('/alerts/risk-override', { district, riskLevel: newRiskLevel });
            await fetchRiskData(); // Re-fetch all data to apply overriding logic from backend
        } catch (err) {
            console.error('Failed to update risk override:', err);
            alert('Failed to update risk level. Check console.');
        } finally {
            setUpdatingOverride(false);
        }
    };

    const getRiskForDistrict = useCallback((districtName) => {
        return riskData.find(d =>
            d.district.toLowerCase() === districtName.toLowerCase()
        ) || { risk: 'Safe', description: 'No data available', score: 0, eventCount: 0 };
    }, [riskData]);

    const styleFeature = useCallback((feature) => {
        const district = feature.properties.district;
        const risk = getRiskForDistrict(district);
        return {
            fillColor: RISK_COLORS[risk.risk] || RISK_COLORS.Safe,
            weight: 2,
            opacity: 0.8,
            color: '#ffffff30',
            fillOpacity: 0.45,
        };
    }, [getRiskForDistrict]);

    const onEachFeature = useCallback((feature, layer) => {
        const district = feature.properties.district;
        const risk = getRiskForDistrict(district);

        layer.bindTooltip(`<strong>${district}</strong><br/>Risk: ${risk.risk}`, {
            sticky: true,
            className: 'leaflet-tooltip-dark'
        });

        layer.on({
            click: () => {
                setSelectedZone({ district, ...risk });
            },
            mouseover: (e) => {
                e.target.setStyle({ weight: 3, fillOpacity: 0.65, color: '#ffffff80' });
            },
            mouseout: (e) => {
                e.target.setStyle({ weight: 2, fillOpacity: 0.45, color: '#ffffff30' });
            }
        });
    }, [getRiskForDistrict]);

    const highRiskCount = riskData.filter(d => d.risk === 'High').length;
    const moderateCount = riskData.filter(d => d.risk === 'Moderate').length;
